import{_ as e,o as s,c as t,a0 as i}from"./chunks/framework.CWk8AOcY.js";const k=JSON.parse('{"title":"多机集群部署","description":"","frontmatter":{},"headers":[],"relativePath":"guide/multi-node-deploy.md","filePath":"zh/guide/multi-node-deploy.md"}'),d={name:"guide/multi-node-deploy.md"};function l(n,a,o,h,p,c){return s(),t("div",null,[...a[0]||(a[0]=[i(`<h1 id="多机集群部署" tabindex="-1">多机集群部署 <a class="header-anchor" href="#多机集群部署" aria-label="Permalink to &quot;多机集群部署&quot;">​</a></h1><p>本指南介绍如何将单机 Cube Sandbox 部署扩展为多机集群，通过添加<strong>计算节点</strong>来实现。计算节点只运行沙箱运行时组件（<code>Cubelet</code>、<code>network-agent</code>、<code>CubeShim</code>），并向第一台机器上的控制面注册。</p><div class="tip custom-block"><p class="custom-block-title">前置条件</p><p>添加计算节点前，你必须先通过<a href="./self-build-deploy.html">本地构建部署指南</a>完成控制节点的部署。</p></div><h2 id="架构概览" tabindex="-1">架构概览 <a class="header-anchor" href="#架构概览" aria-label="Permalink to &quot;架构概览&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────┐</span></span>
<span class="line"><span>│              控制节点                     │</span></span>
<span class="line"><span>│  CubeMaster, cube-api, CubeProxy,      │</span></span>
<span class="line"><span>│  CoreDNS, MySQL, Redis,                │</span></span>
<span class="line"><span>│  Cubelet, network-agent                 │</span></span>
<span class="line"><span>└──────────────────┬──────────────────────┘</span></span>
<span class="line"><span>                   │  /internal/meta API</span></span>
<span class="line"><span>       ┌───────────┼───────────┐</span></span>
<span class="line"><span>       ▼           ▼           ▼</span></span>
<span class="line"><span>┌────────────┐┌────────────┐┌────────────┐</span></span>
<span class="line"><span>│ 计算节点 #1 ││ 计算节点 #2 ││ 计算节点 #N │</span></span>
<span class="line"><span>│ Cubelet    ││ Cubelet    ││ Cubelet    │</span></span>
<span class="line"><span>│ net-agent  ││ net-agent  ││ net-agent  │</span></span>
<span class="line"><span>└────────────┘└────────────┘└────────────┘</span></span></code></pre></div><ul><li><strong>控制节点</strong>运行完整技术栈：编排调度（CubeMaster）、API 网关（cube-api）、代理（CubeProxy + CoreDNS）、数据库（MySQL + Redis），同时自身也作为计算节点。</li><li>每个<strong>计算节点</strong>只运行 <code>Cubelet</code> 和 <code>network-agent</code>，向控制面 <code>CubeMaster</code> 注册并接收沙箱调度请求。</li></ul><h2 id="前置条件" tabindex="-1">前置条件 <a class="header-anchor" href="#前置条件" aria-label="Permalink to &quot;前置条件&quot;">​</a></h2><p>每台计算节点需满足与控制节点相同的硬件和软件要求：</p><ul><li><strong>物理机或裸金属服务器</strong>（不支持嵌套虚拟化）</li><li><strong>x86_64</strong> 架构，<strong>已启用 KVM</strong>（<code>ls /dev/kvm</code>）</li><li><strong>Docker</strong> 已安装并运行</li><li>到控制节点的<strong>网络连通性</strong>（默认需访问 <code>CubeMaster</code> 的 <code>8089</code> 端口）</li></ul><p>完整要求列表请参阅<a href="./self-build-deploy.html#前置条件">本地构建部署 — 前置条件</a>。</p><h2 id="第一步-准备发布包" tabindex="-1">第一步：准备发布包 <a class="header-anchor" href="#第一步-准备发布包" aria-label="Permalink to &quot;第一步：准备发布包&quot;">​</a></h2><p>使用与控制节点<strong>相同的发布包</strong>。将其拷贝到计算节点并解压：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tar</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -xzf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cube-sandbox-one-click-</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">versio</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.tar.gz</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cube-sandbox-one-click-</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">versio</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><h2 id="第二步-配置环境变量" tabindex="-1">第二步：配置环境变量 <a class="header-anchor" href="#第二步-配置环境变量" aria-label="Permalink to &quot;第二步：配置环境变量&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> env.example</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .env</span></span></code></pre></div><p>编辑 <code>.env</code>，设置以下变量：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ONE_CLICK_DEPLOY_ROLE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">compute</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CUBE_SANDBOX_NODE_IP</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">当前节点IP</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ONE_CLICK_CONTROL_PLANE_IP</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">控制节点IP</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><table tabindex="0"><thead><tr><th>变量</th><th>说明</th></tr></thead><tbody><tr><td><code>ONE_CLICK_DEPLOY_ROLE</code></td><td>计算节点必须设为 <code>compute</code></td></tr><tr><td><code>CUBE_SANDBOX_NODE_IP</code></td><td>当前节点主网卡 IP</td></tr><tr><td><code>ONE_CLICK_CONTROL_PLANE_IP</code></td><td>控制节点 IP，自动拼接为 <code>&lt;ip&gt;:8089</code> 作为 CubeMaster 地址</td></tr></tbody></table><p>如果 CubeMaster 使用非默认端口，也可以显式指定：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ONE_CLICK_CONTROL_PLANE_CUBEMASTER_ADDR</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">控制节点IP</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">:8089</span></span></code></pre></div><p>同时设置时，<code>ONE_CLICK_CONTROL_PLANE_CUBEMASTER_ADDR</code> 优先级高于 <code>ONE_CLICK_CONTROL_PLANE_IP</code>。</p><h2 id="第三步-安装" tabindex="-1">第三步：安装 <a class="header-anchor" href="#第三步-安装" aria-label="Permalink to &quot;第三步：安装&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./install-compute.sh</span></span></code></pre></div><p>计算节点安装脚本会：</p><ol><li>只安装 <code>Cubelet</code>、<code>network-agent</code>、<code>cube-shim</code>、<code>cube-image</code>、<code>cube-kernel-scf</code> 和运行时脚本</li><li>只启动宿主机进程：<code>network-agent</code>、<code>cubelet</code></li><li>自动把 <code>Cubelet</code> 的 <code>meta_server_endpoint</code> 指向控制面 <code>CubeMaster</code></li><li>通过控制面的 <code>/internal/meta</code> 接口注册节点并上报状态</li></ol><h2 id="验证部署" tabindex="-1">验证部署 <a class="header-anchor" href="#验证部署" aria-label="Permalink to &quot;验证部署&quot;">​</a></h2><h3 id="健康检查" tabindex="-1">健康检查 <a class="header-anchor" href="#健康检查" aria-label="Permalink to &quot;健康检查&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./smoke.sh</span></span></code></pre></div><p>计算节点模式下，<code>quickcheck.sh</code> 会验证：</p><ul><li>本机 <code>network-agent</code> 健康状态</li><li>控制面 <code>CubeMaster</code> 可达</li><li>当前节点已出现在控制面的 <code>/internal/meta/nodes/{node_id}</code> 中</li></ul><h3 id="从控制节点验证" tabindex="-1">从控制节点验证 <a class="header-anchor" href="#从控制节点验证" aria-label="Permalink to &quot;从控制节点验证&quot;">​</a></h3><p>在控制节点上确认计算节点已注册：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:8089/internal/meta/nodes</span></span></code></pre></div><p>返回结果中应包含计算节点的 IP 和健康状态。</p><h2 id="常用操作" tabindex="-1">常用操作 <a class="header-anchor" href="#常用操作" aria-label="Permalink to &quot;常用操作&quot;">​</a></h2><h3 id="停止计算节点服务" tabindex="-1">停止计算节点服务 <a class="header-anchor" href="#停止计算节点服务" aria-label="Permalink to &quot;停止计算节点服务&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./down.sh</span></span></code></pre></div><p>计算节点模式下，该命令只会停止 <code>cubelet</code> 和 <code>network-agent</code>，不影响控制面或其他计算节点。</p><h3 id="重新安装" tabindex="-1">重新安装 <a class="header-anchor" href="#重新安装" aria-label="Permalink to &quot;重新安装&quot;">​</a></h3><p>直接再次运行 <code>install-compute.sh</code> 即可。安装脚本会自动停止已有部署再进行安装。</p><h3 id="查看日志" tabindex="-1">查看日志 <a class="header-anchor" href="#查看日志" aria-label="Permalink to &quot;查看日志&quot;">​</a></h3><table tabindex="0"><thead><tr><th>组件</th><th>日志路径</th></tr></thead><tbody><tr><td>Cubelet</td><td><code>/data/log/Cubelet/</code></td></tr><tr><td>CubeShim</td><td><code>/data/log/CubeShim/</code></td></tr><tr><td>Hypervisor (VMM)</td><td><code>/data/log/CubeVmm/</code></td></tr><tr><td>运行时 PID 文件</td><td><code>/var/run/cube-sandbox-one-click/</code></td></tr><tr><td>进程标准输出/错误</td><td><code>/var/log/cube-sandbox-one-click/</code></td></tr></tbody></table><p>控制节点的日志路径请参阅<a href="./self-build-deploy.html#查看日志">本地构建部署 — 查看日志</a>。</p><h2 id="配置参考" tabindex="-1">配置参考 <a class="header-anchor" href="#配置参考" aria-label="Permalink to &quot;配置参考&quot;">​</a></h2><p>计算节点使用相同的 <code>.env</code> 文件格式。以下变量与计算节点部署特别相关：</p><table tabindex="0"><thead><tr><th>变量</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><code>ONE_CLICK_DEPLOY_ROLE</code></td><td><code>control</code></td><td>计算节点必须设为 <code>compute</code></td></tr><tr><td><code>ONE_CLICK_CONTROL_PLANE_IP</code></td><td>空</td><td>控制节点 IP，默认拼接为 <code>&lt;ip&gt;:8089</code></td></tr><tr><td><code>ONE_CLICK_CONTROL_PLANE_CUBEMASTER_ADDR</code></td><td>空</td><td>显式指定 CubeMaster 地址，优先级高于 <code>ONE_CLICK_CONTROL_PLANE_IP</code></td></tr><tr><td><code>CUBE_SANDBOX_NODE_IP</code></td><td><code>10.0.0.10</code></td><td><strong>必须修改。</strong> 当前节点主网卡 IP</td></tr><tr><td><code>ONE_CLICK_INSTALL_PREFIX</code></td><td><code>/usr/local/services/cubetoolbox</code></td><td>安装目录</td></tr><tr><td><code>ONE_CLICK_RUN_QUICKCHECK</code></td><td><code>1</code></td><td>安装后是否执行健康检查</td></tr></tbody></table><p>完整配置参考（构建选项、数据库、代理等）请参阅<a href="./self-build-deploy.html#配置参考">本地构建部署 — 配置参考</a>。</p><h2 id="故障排查" tabindex="-1">故障排查 <a class="header-anchor" href="#故障排查" aria-label="Permalink to &quot;故障排查&quot;">​</a></h2><h3 id="计算节点无法连接-cubemaster" tabindex="-1">计算节点无法连接 CubeMaster <a class="header-anchor" href="#计算节点无法连接-cubemaster" aria-label="Permalink to &quot;计算节点无法连接 CubeMaster&quot;">​</a></h3><p>检查网络连通性：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">控制节点I</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">P</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">:8089/internal/meta/nodes</span></span></code></pre></div><p>如果失败，请检查：</p><ul><li>控制节点的防火墙规则（<code>8089</code> 端口需可访问）</li><li><code>.env</code> 中 <code>ONE_CLICK_CONTROL_PLANE_IP</code> 或 <code>ONE_CLICK_CONTROL_PLANE_CUBEMASTER_ADDR</code> 的值</li></ul><h3 id="节点未出现在控制面" tabindex="-1">节点未出现在控制面 <a class="header-anchor" href="#节点未出现在控制面" aria-label="Permalink to &quot;节点未出现在控制面&quot;">​</a></h3><p>如果 <code>smoke.sh</code> 本地通过但控制面上看不到该节点：</p><ol><li>检查 Cubelet 日志：<code>/data/log/Cubelet/</code></li><li>确认 Cubelet 配置中的 <code>meta_server_endpoint</code> 指向正确的 CubeMaster 地址</li><li>确保 <code>CUBE_SANDBOX_NODE_IP</code> 设为可路由的 IP（不是 <code>127.0.0.1</code>）</li></ol><p>通用故障排查（Docker、KVM、DNS 等）请参阅<a href="./self-build-deploy.html#故障排查">本地构建部署 — 故障排查</a>。</p>`,57)])])}const b=e(d,[["render",l]]);export{k as __pageData,b as default};
